UPDATE entities SET is_featured = true, home_display_order = 1 WHERE slug = 'rahul-sharma-mp';
UPDATE entities SET is_featured = true, home_display_order = 2 WHERE slug = 'priya-verma-mla';
UPDATE entities SET is_featured = true, home_display_order = 3 WHERE slug = 'amit-singh-mp';

UPDATE districts SET is_featured = true, home_display_order = 1 WHERE slug = 'jaipur';
UPDATE districts SET is_featured = true, home_display_order = 2 WHERE slug = 'lucknow';
UPDATE districts SET is_featured = true, home_display_order = 3 WHERE slug = 'varanasi';

UPDATE ai_insights SET home_display_order = 1
WHERE title_en = 'Jaipur District Development Index Analysis';
UPDATE ai_insights SET home_display_order = 2
WHERE title_en = 'Parliamentary Performance: Rahul Sharma 2024';

INSERT INTO media_mappings (media_link_id, mapping_type, section_key, display_context, audience_scope, display_order, is_primary, created_at)
SELECT ml.id, 'SECTION', 'HOME', 'HOME', 'NATIONAL', 1, true, NOW()
FROM media_links ml WHERE ml.source_url = 'https://www.youtube.com/watch?v=nl-pol-01' LIMIT 1;

INSERT INTO media_mappings (media_link_id, mapping_type, section_key, display_context, audience_scope, display_order, is_primary, created_at)
SELECT ml.id, 'SECTION', 'HOME', 'HOME', 'NATIONAL', 2, true, NOW()
FROM media_links ml WHERE ml.source_url = 'https://www.instagram.com/reel/nl-pol-02/' LIMIT 1;

INSERT INTO media_mappings (media_link_id, mapping_type, section_key, display_context, audience_scope, display_order, is_primary, created_at)
